import React from 'react';

function Header() {
  const currentDate = new Date();
  const weekday = currentDate.toLocaleDateString('en-GB', { weekday: 'long' });
  const day = currentDate.getDate();
  const month = currentDate.toLocaleDateString('en-GB', { month: 'long' });
  const year = currentDate.getFullYear();

  return (
    <header className="relative flex items-center justify-between px-6 py-4 bg-gradient-to-r from-purple-700 via-indigo-700 to-purple-900 shadow-lg">

      {/* ✅ KRAI text with Montserrat font */}
      <div
        className="text-black text-3xl font-bold bg-transparent px-2 py-1"
        style={{ fontFamily: "'Montserrat', sans-serif" }}
      >
        KRAI
      </div>

      <div className="text-center flex-1">
        <h1 className="text-3xl font-bold text-white">KRAI's BOT</h1>
        <br />
        <p className="text-gray-300 text-sm">
          AI-Powered Audio & Text File Transcription with Summarization
        </p>
      </div>

      <div className="w-10"></div>

      <div className="absolute bottom-2 right-6 text-right text-white">
        <p className="text-xl font-bold">{weekday}</p>
        <p className="text-sm">{`${day} ${month} ${year}`}</p>
      </div>
    </header>
  );
}

export default Header;
